const resolveEntityIdWithFallback = (hass, entityId) => {
  if (!hass || !entityId) return entityId;
  const states = hass.states || {};
  if (states[entityId]) return entityId;
  const fallback = LEGACY_ENTITY_ID_FALLBACKS[entityId];
  if (fallback && states[fallback]) return fallback;
  return entityId;
};

const getEntityStateWithFallback = (hass, entityId) => {
  if (!hass || !entityId) return null;
  const resolvedId = resolveEntityIdWithFallback(hass, entityId);
  return hass.states?.[resolvedId] || null;
};

const isUnavailableLikeEntityState = (entityState) => {
  const state = String(entityState?.state || '').trim().toLowerCase();
  return state === 'unavailable' || state === 'unknown';
};

const DEFAULT_F1TV_AUTH_STATUS_ENTITY = 'sensor.f1_f1tv_token_status';
const F1TV_AUTH_ATTENTION_STATES = new Set(['expired', 'invalid', 'rejected']);

const findF1TvAuthStatusEntity = (hass) => {
  const states = hass?.states || {};
  const candidates = Object.values(states).filter((entityState) => {
    const entityId = String(entityState?.entity_id || '').toLowerCase();
    const attrs = entityState?.attributes || {};
    return entityId.includes('f1tv_token_status')
      || attrs.auth_configured !== undefined
      || attrs.used_for_live_timing !== undefined;
  });
  if (candidates.length === 0) return null;
  candidates.sort((a, b) => {
    const aId = String(a?.entity_id || '').toLowerCase();
    const bId = String(b?.entity_id || '').toLowerCase();
    if (aId === DEFAULT_F1TV_AUTH_STATUS_ENTITY) return -1;
    if (bId === DEFAULT_F1TV_AUTH_STATUS_ENTITY) return 1;
    if (aId.includes('f1tv_token_status') && !bId.includes('f1tv_token_status')) return -1;
    if (!aId.includes('f1tv_token_status') && bId.includes('f1tv_token_status')) return 1;
    return aId.localeCompare(bId);
  });
  return candidates[0];
};

const resolveF1TvAuthStatus = (hass, entityId) => {
  const configuredEntityId = String(entityId || DEFAULT_F1TV_AUTH_STATUS_ENTITY).trim()
    || DEFAULT_F1TV_AUTH_STATUS_ENTITY;
  const entityState = getEntityStateWithFallback(hass, configuredEntityId)
    || findF1TvAuthStatusEntity(hass);
  if (!entityState || isUnavailableLikeEntityState(entityState)) {
    return {
      available: false,
      configured: false,
      state: null,
      usedForLiveTiming: false,
      needsAttention: false,
    };
  }

  const state = String(entityState.state || '').trim().toLowerCase();
  const attrs = entityState.attributes || {};
  const configured = attrs.auth_configured === true
    || (attrs.auth_configured !== false && Boolean(state) && state !== 'not_configured');

  return {
    available: true,
    configured,
    state,
    usedForLiveTiming: attrs.used_for_live_timing === true,
    needsAttention: F1TV_AUTH_ATTENTION_STATES.has(state),
  };
};

const buildF1DataAvailabilityNotice = (hass, config, feature) => {
  const isPitStop = feature === 'pit_stops';
  const authStatus = resolveF1TvAuthStatus(hass, config?.auth_status_entity);
  const noticeHidden = config?.show_availability_notice === false;

  if (authStatus.needsAttention) {
    return {
      tone: 'warning',
      message: isPitStop
        ? 'F1TV access needs attention, so live pit stop data is hidden. Replay data remains available.'
        : 'F1TV access needs attention, so live predicted points are hidden. Replay data remains available.',
    };
  }

  if (noticeHidden) return null;

  if (!authStatus.available) {
    return {
      tone: 'info',
      message: isPitStop
        ? 'Pit stop data is available in Replay Mode or live when F1TV access is active.'
        : 'Predicted points are available in Replay Mode or live when F1TV access is active.',
    };
  }

  if (!authStatus.configured || authStatus.state === 'not_configured') {
    return {
      tone: 'info',
      message: isPitStop
        ? 'Connect F1TV access to show live pit stop data. Replay data remains available.'
        : 'Connect F1TV access to show live predicted points. Replay data remains available.',
    };
  }

  return null;
};

const resolveF1DataAvailabilityNotice = (
  hass,
  config,
  feature,
  dataUnavailable,
  featureEnabled = true,
) => {
  if (!dataUnavailable || !featureEnabled) return null;
  return buildF1DataAvailabilityNotice(hass, config, feature);
};

const renderF1AvailabilityNotice = (notice, className) => (
  notice
    ? html`<div class="${className} ${notice.tone}">${notice.message}</div>`
    : null
);

const getStateAgeSeconds = (state, field = 'last_changed') => {
  const rawValue = state?.[field] || state?.last_updated || null;
  if (!rawValue) return null;
  const timestamp = new Date(rawValue);
  if (Number.isNaN(timestamp.getTime())) return null;
  return Math.max(0, (Date.now() - timestamp.getTime()) / 1000);
};

const POST_SESSION_RETENTION_SECONDS = 600;
const TERMINAL_SESSION_STATUSES = new Set(['finished', 'finalised', 'ended']);

const isTerminalSessionStatus = (sessionStatusState) => (
  TERMINAL_SESSION_STATUSES.has(String(sessionStatusState?.state || '').trim().toLowerCase())
);

const getPostSessionAgeSeconds = (sessionState, sessionStatusState, stateMatchesLabel) => {
  const primaryState = stateMatchesLabel ? sessionStatusState : sessionState;
  const fallbackState = stateMatchesLabel ? sessionState : sessionStatusState;
  const primaryAge = getStateAgeSeconds(primaryState, 'last_changed');
  if (primaryAge !== null) return primaryAge;
  return getStateAgeSeconds(fallbackState, 'last_changed');
};

const isSessionWithinPostSessionRetention = (
  sessionState,
  sessionStatusState,
  labelMatcher,
) => {
  if (!isTerminalSessionStatus(sessionStatusState)) {
    return false;
  }
  const state = String(sessionState?.state || '').trim().toLowerCase();
  const stateMatchesLabel = labelMatcher(state);
  const lastLabel = String(sessionState?.attributes?.last_label || '').trim().toLowerCase();
  if (!stateMatchesLabel && !labelMatcher(lastLabel)) {
    return false;
  }

  const ageSeconds = getPostSessionAgeSeconds(
    sessionState,
    sessionStatusState,
    stateMatchesLabel,
  );
  return ageSeconds !== null && ageSeconds <= POST_SESSION_RETENTION_SECONDS;
};

const meaningfulSessionLabel = (value) => {
  const text = String(value || '').trim();
  if (!text) return '';
  const normalized = text.toLowerCase();
  if (normalized === 'unknown' || normalized === 'unavailable' || normalized === 'none') {
    return '';
  }
  return text;
};

const resolveSessionSnapshotKey = (sessionState, fallbackLabel = '') => {
  const attrs = sessionState?.attributes || {};
  const label = meaningfulSessionLabel(sessionState?.state)
    || meaningfulSessionLabel(attrs.last_label)
    || meaningfulSessionLabel(attrs.resolved_label)
    || meaningfulSessionLabel(attrs.name)
    || meaningfulSessionLabel(fallbackLabel);
  if (!label) return null;
  const meeting = attrs.meeting_key
    || attrs.meeting_name
    || attrs.meeting_location
    || attrs.circuit_short_name
    || '';
  const start = attrs.start
    || attrs.start_time
    || attrs.start_time_utc
    || attrs.start_utc
    || '';
  return [label, meeting, start].map((part) => String(part || '').trim()).join('|');
};

const cloneTimingSnapshotRows = (rows) => (
  Array.isArray(rows)
    ? rows.map((row) => ({
      ...row,
      team_logo: row?.team_logo ? { ...row.team_logo } : row?.team_logo,
    }))
    : []
);

const syncTimingSnapshotSession = (card, sessionKey) => {
  if (!card) return;
  const normalizedSessionKey = sessionKey || null;
  if (card._f1SectorSessionKey !== normalizedSessionKey) {
    card._f1SectorSessionKey = normalizedSessionKey;
    card._f1SectorLapCache = new Map();
  }
  if (!sessionKey || card._postSessionSnapshot?.key !== sessionKey) {
    card._postSessionSnapshot = null;
  }
};

const rememberTimingSnapshot = (card, sessionKey, payload) => {
  const rows = cloneTimingSnapshotRows(payload?.rows);
  if (!card || !sessionKey || rows.length === 0) return;
  card._postSessionSnapshot = {
    ...payload,
    key: sessionKey,
    rows,
  };
};

const getRetainedTimingSnapshot = (card, sessionKey, retain) => {
  if (!card || !retain || !sessionKey || card._postSessionSnapshot?.key !== sessionKey) {
    return null;
  }
  return {
    ...card._postSessionSnapshot,
    rows: cloneTimingSnapshotRows(card._postSessionSnapshot.rows),
  };
};

const shouldKeepSessionCardVisible = (
  hass,
  sessionState,
  sessionStatusState,
  labelMatcher,
  keepAliveStates = [],
) => {
  const state = String(sessionState?.state || '').trim().toLowerCase();
  const stateMatchesLabel = labelMatcher(state);
  const terminalRetention = isSessionWithinPostSessionRetention(
    sessionState,
    sessionStatusState,
    labelMatcher,
  );
  if (stateMatchesLabel) {
    if (isTerminalSessionStatus(sessionStatusState)) {
      return terminalRetention;
    }
    return true;
  }

  const lastLabel = String(sessionState?.attributes?.last_label || '').trim().toLowerCase();
  if (!labelMatcher(lastLabel)) {
    return false;
  }

  const sessionStatus = String(sessionStatusState?.state || '').trim().toLowerCase();
  if (keepAliveStates.includes(sessionStatus)) {
    return true;
  }

  return terminalRetention;
};

const asEntityList = (value) => {
  if (Array.isArray(value)) return value;
  if (!value || typeof value !== 'object') return [];
  return Object.values(value).filter((entry) => entry && typeof entry === 'object');
};

const hasCollectionEntries = (value) => {
  if (Array.isArray(value)) return value.length > 0;
  if (!value || typeof value !== 'object') return false;
  return Object.keys(value).length > 0;
};

const normalizeDriverDisplayText = (value) => {
  const text = String(value ?? '').replace(/\s+/g, ' ').trim();
  return text || null;
};

const normalizeDriverCode = (value) => {
  const text = normalizeDriverDisplayText(value);
  return text ? text.toUpperCase() : null;
};

const resolveDriverFullNameFromSource = (source) => {
  if (!source || typeof source !== 'object') return null;

  const direct = [
    source.full_name,
    source.driver_name,
    source.fullName,
    source.broadcast_name,
    source.name,
  ]
    .map(normalizeDriverDisplayText)
    .find(Boolean);
  if (direct) return direct;

  const first = normalizeDriverDisplayText(
    source.first_name ?? source.firstName ?? source.given_name ?? source.givenName,
  );
  const last = normalizeDriverDisplayText(
    source.last_name ?? source.lastName ?? source.family_name ?? source.familyName,
  );
  if (first || last) {
    return [first, last].filter(Boolean).join(' ');
  }

  return null;
};

const resolveDriverDisplay = (sources, showFullName = false, fallback = '--') => {
  const candidates = Array.isArray(sources) ? sources : [sources];
  let tla = null;
  let fullName = null;

  for (const source of candidates) {
    if (!tla) {
      tla = normalizeDriverCode(source?.tla ?? source?.driver_tla ?? source?.code ?? source?.Tla);
    }
    if (!fullName) {
      fullName = resolveDriverFullNameFromSource(source);
    }
    if (tla && fullName) break;
  }

  const canUseFullName = Boolean(
    fullName && (!tla || normalizeDriverCode(fullName) !== tla),
  );

  if (showFullName && canUseFullName) {
    return {
      label: fullName,
      tla,
      full_name: fullName,
      use_full_name: true,
    };
  }

  return {
    label: tla || fullName || fallback,
    tla,
    full_name: fullName,
    use_full_name: false,
  };
};

const isRaceLikeLabel = (value) => String(value || '').trim().toLowerCase() === 'race';

const isRaceSessionActive = (sessionState, sessionStatusState) => {
  const status = String(sessionStatusState?.state || '').trim().toLowerCase();
  if (status !== 'live' && status !== 'suspended') {
    return false;
  }

  return isRaceLikeLabel(sessionState?.state) || isRaceLikeLabel(sessionState?.attributes?.last_label);
};

const isNoSpoilerModeActive = (entityState) => String(entityState?.state || '').trim().toLowerCase() === 'on';

const DEFAULT_NO_SPOILER_ENTITY = 'switch.f1_no_spoiler_mode';

const getNoSpoilerStateForCard = (hass, config) => {
  const configuredEntity = String(config?.no_spoiler_entity || DEFAULT_NO_SPOILER_ENTITY).trim();
  const entityId = configuredEntity || DEFAULT_NO_SPOILER_ENTITY;
  return getEntityStateWithFallback(hass, entityId);
};

const isNoSpoilerModeActiveForCard = (hass, config) => (
  isNoSpoilerModeActive(getNoSpoilerStateForCard(hass, config))
);

const renderNoSpoilerOverlay = () => html`
  <div class="f1-no-spoiler-overlay" role="status" aria-live="polite">
    <div class="f1-no-spoiler-kicker">No Spoiler Mode</div>
    <div class="f1-no-spoiler-title">No Spoiler Mode is active</div>
    <div class="f1-no-spoiler-copy">Live and results data is frozen until the switch is turned off.</div>
  </div>
`;

const renderWithNoSpoilerOverlay = (content, active) => (
  active
    ? html`
      <div class="f1-no-spoiler-host active">
        ${content}
        ${renderNoSpoilerOverlay()}
      </div>
    `
    : content
);

const installNoSpoilerOverlay = (CardClass) => {
  if (!CardClass?.prototype || CardClass.prototype._f1NoSpoilerOverlayInstalled) {
    return;
  }

  const proto = CardClass.prototype;
  const originalSetConfig = proto.setConfig;
  const originalRender = proto.render;

  if (typeof originalRender !== 'function') {
    return;
  }

  proto.setConfig = function setConfig(config = {}) {
    if (typeof originalSetConfig === 'function') {
      originalSetConfig.call(this, config);
    } else {
      this.config = { ...config };
    }

    if (this.config && !this.config.no_spoiler_entity) {
      this.config.no_spoiler_entity = DEFAULT_NO_SPOILER_ENTITY;
    }
  };

  proto.render = function render(...args) {
    const content = originalRender.call(this, ...args);
    return renderWithNoSpoilerOverlay(
      content,
      isNoSpoilerModeActiveForCard(this.hass, this.config),
    );
  };

  proto._f1NoSpoilerOverlayInstalled = true;
};

const measureRenderedCardHeight = (host) => {
  const card = host?.renderRoot?.querySelector?.('ha-card');
  const content = card?.firstElementChild;
  const cardHeight = card?.getBoundingClientRect?.().height ?? 0;
  const contentHeight = content?.scrollHeight ?? 0;
  return Math.max(cardHeight, contentHeight);
};

const measureRenderedCardWidth = (host) => {
  const hostWidth = host?.getBoundingClientRect?.().width ?? 0;
  const card = host?.renderRoot?.querySelector?.('ha-card');
  const content = card?.firstElementChild;
  const cardWidth = card?.clientWidth || card?.getBoundingClientRect?.().width || 0;
  const measuredWidth = Math.max(hostWidth, cardWidth);
  if (measuredWidth > 0) {
    return measuredWidth;
  }
  return content?.getBoundingClientRect?.().width ?? 0;
};

const DEFAULT_RESPONSIVE_BREAKPOINTS = {
  narrow: 480,
  medium: 760,
};

const getResponsiveBreakpoints = (host) => {
  const custom = typeof host?._responsiveLayoutBreakpoints === 'function'
    ? host._responsiveLayoutBreakpoints()
    : host?._responsiveLayoutBreakpoints;
  return {
    ...DEFAULT_RESPONSIVE_BREAKPOINTS,
    ...(custom || {}),
  };
};

const resolveResponsiveLayoutMode = (width, breakpoints) => {
  if (width > 0 && width <= breakpoints.narrow) {
    return 'narrow';
  }
  if (width > 0 && width <= breakpoints.medium) {
    return 'medium';
  }
  return 'wide';
};

const getResponsiveLayoutMode = (host) => {
  if (!host) return 'wide';
  const width = host._responsiveCardWidth || measureRenderedCardWidth(host);
  return resolveResponsiveLayoutMode(width, getResponsiveBreakpoints(host));
};

const updateResponsiveLayout = (host) => {
  const width = measureRenderedCardWidth(host);
  if (width <= 0) {
    return false;
  }

  const nextMode = resolveResponsiveLayoutMode(width, getResponsiveBreakpoints(host));
  const previousMode = host._responsiveLayoutMode || 'wide';
  host._responsiveCardWidth = width;

  if (nextMode === previousMode) {
    return false;
  }

  host._responsiveLayoutMode = nextMode;
  host.requestUpdate?.();
  return true;
};

const attachSectionsHeightObserver = (host) => {
  if (!host?.isConnected || typeof ResizeObserver === 'undefined') {
    return;
  }

  const card = host.renderRoot?.querySelector?.('ha-card');
  if (!card) {
    return;
  }

  if (!host._sectionsHeightObserver) {
    host._sectionsHeightObserver = new ResizeObserver(() => {
      updateSectionsHeight(host);
    });
  }

  if (host._sectionsObservedCard === card) {
    return;
  }

  detachSectionsHeightObserver(host);
  host._sectionsObservedCard = card;
  host._sectionsHeightObserver.observe(card);
};

const detachSectionsHeightObserver = (host) => {
  if (host?._sectionsHeightObserver && host?._sectionsObservedCard) {
    host._sectionsHeightObserver.unobserve(host._sectionsObservedCard);
  }
  host._sectionsObservedCard = undefined;
};

const attachResponsiveLayoutObserver = (host) => {
  if (!host?.isConnected || typeof ResizeObserver === 'undefined') {
    return;
  }

  const card = host.renderRoot?.querySelector?.('ha-card');
  if (!card) {
    return;
  }

  if (!host._responsiveLayoutObserver) {
    host._responsiveLayoutObserver = new ResizeObserver(() => {
      const layoutChanged = updateResponsiveLayout(host);
      if (layoutChanged) {
        Promise.resolve(host.updateComplete)
          .then(() => updateSectionsHeight(host))
          .catch(() => {});
        return;
      }
      updateSectionsHeight(host);
    });
  }

  if (host._responsiveObservedCard === card) {
    return;
  }

  detachResponsiveLayoutObserver(host);
  host._responsiveObservedCard = card;
  host._responsiveLayoutObserver.observe(card);
};

const detachResponsiveLayoutObserver = (host) => {
  if (host?._responsiveLayoutObserver && host?._responsiveObservedCard) {
    host._responsiveLayoutObserver.unobserve(host._responsiveObservedCard);
  }
  host._responsiveObservedCard = undefined;
};

const updateSectionsHeight = (host) => {
  const measuredHeight = measureRenderedCardHeight(host);
  const nextHeight = measuredHeight > 0 ? Math.ceil(measuredHeight) : 0;

  if (nextHeight <= 0 || nextHeight === host._sectionsMeasuredHeight) {
    return;
  }

  host._sectionsMeasuredHeight = nextHeight;
  host.dispatchEvent(new Event('card-updated', { bubbles: true, composed: true }));
  host.dispatchEvent(new Event('iron-resize', { bubbles: true, composed: true }));
};

const installSectionsAutoHeight = (CardClass, fallbackGridOptions = {}) => {
  const proto = CardClass.prototype;
  const originalDisconnected = proto.disconnectedCallback;
  const originalFirstUpdated = proto.firstUpdated;
  const originalUpdated = proto.updated;
  const originalGetCardSize = proto.getCardSize;
  const originalGetGridOptions = proto.getGridOptions;

  proto.disconnectedCallback = function disconnectedCallback() {
    detachSectionsHeightObserver(this);
    detachResponsiveLayoutObserver(this);
    originalDisconnected?.call(this);
  };

  proto.firstUpdated = function firstUpdated(changedProps) {
    originalFirstUpdated?.call(this, changedProps);
    updateResponsiveLayout(this);
    attachResponsiveLayoutObserver(this);
    attachSectionsHeightObserver(this);
    updateSectionsHeight(this);
  };

  proto.updated = function updated(changedProps) {
    originalUpdated?.call(this, changedProps);

    if (!changedProps?.has?.('hass') && !changedProps?.has?.('config')) {
      return;
    }

    applyF1ThemeMode(this, this.config, this.hass);
    updateResponsiveLayout(this);
    attachResponsiveLayoutObserver(this);
    attachSectionsHeightObserver(this);
    updateSectionsHeight(this);
  };

  proto.getCardSize = async function getCardSize() {
    await this.updateComplete;

    const renderedHeight = measureRenderedCardHeight(this);
    if (renderedHeight > 0) {
      return Math.max(1, Math.ceil(renderedHeight / 50));
    }

    if (typeof originalGetCardSize === 'function') {
      return originalGetCardSize.call(this);
    }

    return fallbackGridOptions.min_rows ?? 1;
  };

  proto.getGridOptions = function getGridOptions() {
    const originalOptions = typeof originalGetGridOptions === 'function'
      ? originalGetGridOptions.call(this)
      : {};
    const merged = {
      columns: 12,
      min_rows: 1,
      ...fallbackGridOptions,
      ...originalOptions,
    };

    // Provide only column sizing here. Avoid returning `rows` so Sections can
    // auto-size height based on content without clipping or overlap.
    delete merged.rows;
    delete merged.fixed_rows;

    return merged;
  };
};

