class F1RaceControlCard extends LitElement {
  static properties = {
    hass: {},
    config: {},
    _currentMessage: { state: true },
    _listMessages: { state: true },
    _listLoading: { state: true },
    _listError: { state: true },
    _isClearing: { state: true },
  };

  static styles = [F1_THEME_STYLES, css`
    /* Animation keyframes */
    @keyframes fadeSlideIn {
      from { opacity: 0; transform: translateX(-8px); }
      to { opacity: 1; transform: translateX(0); }
    }

    @keyframes glowPulse {
      0%, 100% { box-shadow: var(--rc-shadow), 0 0 0 0 rgba(var(--glow-color-rgb, 255, 59, 48), 0.4); }
      50% { box-shadow: var(--rc-shadow), 0 0 16px 4px rgba(var(--glow-color-rgb, 255, 59, 48), 0.5); }
    }

    @keyframes pulse {
      0%, 100% { opacity: 1; }
      50% { opacity: 0.7; }
    }

    @media (prefers-reduced-motion: reduce) {
      *, *::before, *::after {
        animation-duration: 0.01ms !important;
        animation-iteration-count: 1 !important;
        transition-duration: 0.01ms !important;
      }
    }

    :host {
      --rc-bg: var(--f1-card-bg);
      --rc-bg-soft: var(--f1-card-bg-soft);
      --rc-bg-end: var(--f1-card-bg-end);
      --rc-border: var(--f1-card-border);
      --rc-text: var(--f1-card-text);
      --rc-muted: var(--f1-card-muted);
      --rc-red: #ff3b30;
      --rc-shadow: var(--f1-card-compact-shadow);
    }

    ha-card {
      padding: 0;
      background: transparent;
      box-shadow: none;
      border: none;
    }

    .rc-card {
      font-family: var(--f1-card-body-font-family, 'Formula1 Display', 'Titillium Web', Arial, sans-serif);
      display: flex;
      align-items: center;
      flex-wrap: wrap;
      gap: clamp(10px, 2vw, 16px);
      padding: clamp(8px, 1.2vw, 12px) clamp(12px, 2vw, 18px);
      border-radius: var(--ha-card-border-radius, 12px);
      background:
        radial-gradient(circle at 10% 20%, var(--f1-card-panel), transparent 40%),
        linear-gradient(160deg, var(--rc-bg) 0%, var(--rc-bg-soft) 100%);
      border: 1px solid var(--rc-border);
      box-shadow: var(--rc-shadow);
      color: var(--rc-text);
      transition: box-shadow 0.3s ease, border-color 0.3s ease;
      container-type: inline-size;
    }

    .rc-card.critical {
      --glow-color-rgb: 255, 59, 48;
      animation: glowPulse 1.5s ease-in-out infinite;
      border-color: rgba(255, 59, 48, 0.4);
    }

    .rc-card.critical-sc {
      --glow-color-rgb: 255, 149, 0;
      animation: glowPulse 2s ease-in-out infinite;
      border-color: rgba(255, 149, 0, 0.4);
    }

    .rc-fia-logo {
      height: clamp(22px, 3.5vw, 28px);
      width: auto;
      flex-shrink: 0;
      object-fit: contain;
      padding-right: clamp(10px, 1.5vw, 14px);
      border-right: 1px solid var(--f1-card-divider-strong);
    }

    .rc-content {
      flex: 1;
      min-width: 0;
      display: flex;
      align-items: center;
      flex-wrap: wrap;
      gap: clamp(12px, 2vw, 20px);
    }

    .rc-message {
      flex: 1;
      font-weight: 700;
      font-size: clamp(11px, 1.6vw, 13px);
      line-height: 1.3;
      color: var(--rc-text);
      animation: fadeSlideIn 0.3s ease-out;
    }

    .rc-message.category-safetycar {
      color: #ff9500;
    }

    .rc-message.category-penalty {
      color: #f87171;
    }

    .rc-highlight {
      color: var(--rc-red);
    }

    .rc-icon {
      width: clamp(20px, 3vw, 26px);
      height: clamp(20px, 3vw, 26px);
      flex-shrink: 0;
      fill: var(--rc-muted);
    }

    .rc-icon.flag-red { fill: #ff3b30; }
    .rc-icon.flag-yellow { fill: #ffd60a; }
    .rc-icon.flag-blue { fill: #0a84ff; }
    .rc-icon.flag-green { fill: #34c759; }
    .rc-icon.category-sc { fill: #ff9500; }

    .rc-unavailable {
      font-size: clamp(11px, 1.6vw, 13px);
      color: var(--rc-muted);
      padding: clamp(8px, 1.5vw, 12px);
      text-align: center;
    }

    .rc-card.rc-unavailable {
      justify-content: flex-start;
      text-align: center;
      gap: clamp(10px, 2vw, 16px);
    }

    .rc-unavailable-text {
      flex: 1;
      font-weight: 600;
      text-align: center;
      color: var(--rc-muted);
    }

    .rc-queue-indicator {
      font-size: var(--f1-table-meta-font-size, 10px);
      font-weight: 700;
      color: #1a1a1a;
      background: #ffd60a;
      padding: 2px 6px;
      border-radius: 8px;
      border: 1px solid #ffbf00;
      box-shadow: 0 0 8px rgba(255, 214, 10, 0.35);
      flex-shrink: 0;
      animation: pulse 1.5s ease-in-out infinite;
    }

    .rc-list-shell {
      font-family: var(--f1-card-body-font-family, 'Formula1 Display', 'Titillium Web', Arial, sans-serif);
      border-radius: var(--ha-card-border-radius, 12px);
      background:
        radial-gradient(circle at 10% 20%, var(--f1-card-panel), transparent 40%),
        linear-gradient(160deg, var(--rc-bg) 0%, var(--rc-bg-soft) 100%);
      border: 1px solid var(--rc-border);
      box-shadow: var(--rc-shadow);
      color: var(--rc-text);
      overflow: hidden;
      container-type: inline-size;
    }

    .rc-list-topbar {
      display: flex;
      justify-content: space-between;
      align-items: flex-start;
      gap: 14px;
      padding: 14px 16px 12px;
      border-bottom: 1px solid var(--f1-card-divider);
      background: linear-gradient(180deg, var(--f1-card-panel-soft), transparent);
    }

    .rc-list-brand {
      display: flex;
      align-items: center;
      gap: 14px;
      min-width: 0;
      flex: 1;
    }

    .rc-list-title-wrap {
      min-width: 0;
      display: flex;
      flex-direction: column;
      gap: 4px;
    }

    .rc-list-title {
      font-size: clamp(13px, 2vw, 16px);
      font-weight: 700;
      letter-spacing: 0.08em;
      color: var(--rc-text);
      text-transform: uppercase;
    }

    .rc-list-count {
      font-size: var(--f1-table-meta-font-size, 10px);
      font-weight: 700;
      letter-spacing: 0.18em;
      text-transform: uppercase;
      color: var(--rc-muted);
    }

    .rc-list-controls {
      display: flex;
      align-items: center;
      gap: 8px;
      flex-shrink: 0;
    }

    .rc-live-pill {
      display: inline-flex;
      align-items: center;
      justify-content: center;
      min-width: 54px;
      padding: 5px 10px;
      border-radius: 999px;
      border: 1px solid rgba(255, 59, 48, 0.45);
      background: rgba(255, 59, 48, 0.14);
      color: #ff8a84;
      font-size: var(--f1-table-meta-font-size, 10px);
      font-weight: 700;
      letter-spacing: 0.18em;
      text-transform: uppercase;
    }

    .rc-live-pill.saved {
      border-color: var(--f1-card-divider-strong);
      background: var(--f1-card-panel);
      color: var(--rc-muted);
    }

    .rc-clear-button {
      appearance: none;
      border: 1px solid var(--f1-card-divider-strong);
      background: var(--f1-card-panel);
      color: var(--rc-text);
      border-radius: 10px;
      padding: 7px 12px;
      font: inherit;
      font-size: var(--f1-table-meta-font-size, 10px);
      font-weight: 700;
      letter-spacing: 0.18em;
      text-transform: uppercase;
      cursor: pointer;
      transition: background 0.2s ease, border-color 0.2s ease, opacity 0.2s ease;
    }

    .rc-clear-button:hover {
      background: rgba(255, 59, 48, 0.12);
      border-color: rgba(255, 59, 48, 0.25);
    }

    .rc-clear-button:disabled {
      opacity: 0.6;
      cursor: wait;
    }

    .rc-list-body {
      display: flex;
      flex-direction: column;
      gap: 8px;
      padding: 10px;
      overflow-y: auto;
      -webkit-overflow-scrolling: touch;
    }

    .rc-list-empty {
      padding: 18px 14px;
      border-radius: 12px;
      border: 1px dashed var(--f1-card-chip);
      color: var(--rc-muted);
      text-align: center;
      font-size: var(--f1-table-row-font-size, clamp(10px, 1.6vw, 11px));
      letter-spacing: 0.06em;
      text-transform: uppercase;
      background: var(--f1-card-panel-soft);
    }

    .rc-list-row {
      --rc-row-accent: var(--f1-card-divider-strong);
      position: relative;
      display: grid;
      grid-template-columns: minmax(74px, auto) minmax(0, 1fr);
      column-gap: 12px;
      row-gap: 6px;
      align-items: start;
      min-height: 58px;
      padding: 10px 14px 11px 16px;
      border-radius: 12px;
      border: 1px solid var(--f1-card-divider);
      background: var(--f1-card-panel-soft);
      overflow: hidden;
    }

    .rc-list-row::before {
      content: '';
      position: absolute;
      left: 0;
      top: 8px;
      bottom: 8px;
      width: 3px;
      border-radius: 999px;
      background: var(--rc-row-accent);
    }

    .rc-list-row.tone-red {
      --rc-row-accent: #ff3b30;
      background: linear-gradient(135deg, rgba(255, 59, 48, 0.14), rgba(255, 59, 48, 0.04));
    }

    .rc-list-row.tone-yellow {
      --rc-row-accent: #ffd60a;
      background: linear-gradient(135deg, rgba(255, 214, 10, 0.12), rgba(255, 214, 10, 0.03));
    }

    .rc-list-row.tone-blue {
      --rc-row-accent: #0a84ff;
      background: linear-gradient(135deg, rgba(10, 132, 255, 0.12), rgba(10, 132, 255, 0.03));
    }

    .rc-list-row.tone-green {
      --rc-row-accent: #34c759;
      background: linear-gradient(135deg, rgba(52, 199, 89, 0.12), rgba(52, 199, 89, 0.03));
    }

    .rc-list-row.tone-orange {
      --rc-row-accent: #ff9500;
      background: linear-gradient(135deg, rgba(255, 149, 0, 0.12), rgba(255, 149, 0, 0.03));
    }

    .rc-list-meta {
      display: flex;
      flex-direction: column;
      gap: 2px;
      min-width: 0;
      font-size: var(--f1-table-meta-font-size, 10px);
      line-height: 1.25;
      color: var(--rc-muted);
      text-transform: uppercase;
      letter-spacing: 0.1em;
    }

    .rc-list-sequence {
      font-weight: 700;
    }

    .rc-list-time {
      color: var(--rc-red);
      font-weight: 700;
      letter-spacing: 0.08em;
    }

    .rc-list-content {
      display: flex;
      flex-direction: column;
      gap: 4px;
      min-width: 0;
    }

    .rc-list-category {
      color: var(--rc-row-accent);
      font-size: var(--f1-table-meta-font-size, 10px);
      line-height: 1.2;
      font-weight: 700;
      letter-spacing: 0.16em;
      text-transform: uppercase;
    }

    .rc-list-message {
      color: var(--rc-text);
      font-size: 13px;
      line-height: 1.38;
      font-weight: 600;
      word-break: break-word;
    }

    .rc-list-warning {
      padding: 0 16px 10px;
      color: #ffb4ab;
      font-size: var(--f1-table-meta-font-size, 10px);
      letter-spacing: 0.06em;
      text-transform: uppercase;
    }

    @media (max-width: 600px) {
      .rc-list-topbar {
        flex-direction: column;
        align-items: stretch;
      }

      .rc-list-controls {
        justify-content: space-between;
      }

      .rc-list-row {
        grid-template-columns: 1fr;
        row-gap: 6px;
        min-height: 68px;
        padding: 11px 14px 12px 16px;
      }

      .rc-list-meta {
        flex-direction: row;
        align-items: center;
        gap: 8px;
      }
    }

    @container (max-width: 760px) {
      .rc-list-topbar {
        flex-direction: column;
        align-items: stretch;
      }

      .rc-list-controls {
        justify-content: space-between;
        flex-wrap: wrap;
      }

      .rc-list-row {
        grid-template-columns: 1fr;
        row-gap: 6px;
        min-height: 68px;
        padding: 11px 14px 12px 16px;
      }

      .rc-list-meta {
        flex-direction: row;
        align-items: center;
        gap: 8px;
      }
    }
  `];

  constructor() {
    super();
    this._currentMessage = null;
    this._listMessages = [];
    this._listLoading = false;
    this._listError = null;
    this._isClearing = false;
    this._historyQueue = [];
    this._historyIndex = 0;
    this._lastEventId = null;
    this._displayTimer = null;
    this._messageShownAt = 0;
    this._listContextKey = null;
    this._listEventUnsub = null;
    this._listResetUnsub = null;
    this._listLoadToken = 0;
  }

  connectedCallback() {
    super.connectedCallback();
    ensureF1Fonts();
    const syncResult = this._syncRaceControlState();
    if (syncResult && typeof syncResult.catch === 'function') {
      syncResult.catch(() => {});
    }
  }

  disconnectedCallback() {
    super.disconnectedCallback();
    this._clearDisplayTimer();
    this._unsubscribeListEvents();
  }

  _clearDisplayTimer() {
    if (this._displayTimer) {
      clearTimeout(this._displayTimer);
      this._displayTimer = null;
    }
  }

  willUpdate(changedProps) {
    if (changedProps.has('hass') || changedProps.has('config')) {
      const syncResult = this._syncRaceControlState();
      if (syncResult && typeof syncResult.catch === 'function') {
        syncResult.catch(() => {});
      }
    }
  }

  _resetMessageState() {
    this._currentMessage = null;
    this._historyQueue = [];
    this._historyIndex = 0;
    this._lastEventId = null;
    this._messageShownAt = 0;
    this._clearDisplayTimer();
  }

  _resetListState() {
    this._listMessages = [];
    this._listLoading = false;
    this._listError = null;
    this._isClearing = false;
    this._listContextKey = null;
  }

  _getDisplayMode() {
    return this.config?.display_mode === 'list' ? 'list' : 'latest';
  }

  _normalizeListMaxHeight(value) {
    const parsed = Number.parseInt(value, 10);
    if (!Number.isFinite(parsed) || parsed <= 0) {
      return 600;
    }
    return Math.min(2000, Math.max(240, parsed));
  }

  _isListMode() {
    return this._getDisplayMode() === 'list';
  }

  async _syncRaceControlState() {
    const entityId = resolveEntityIdWithFallback(this.hass, this.config?.entity);
    const entity = getEntityStateWithFallback(this.hass, this.config?.entity);

    if (!this._isListMode()) {
      this._unsubscribeListEvents();
      this._resetListState();
      this._syncLatestMessageState(entity);
      return;
    }

    this._clearDisplayTimer();
    this._currentMessage = null;
    this._historyQueue = [];
    this._historyIndex = 0;
    this._lastEventId = null;
    this._messageShownAt = 0;

    if (!entityId || !entity) {
      this._unsubscribeListEvents();
      this._resetListState();
      return;
    }

    const contextKey = `${entityId}|list`;
    if (this._listContextKey !== contextKey) {
      this._unsubscribeListEvents();
      this._listContextKey = contextKey;
      this._listMessages = [];
      this._listLoading = true;
      this._listError = null;
      this._subscribeListEvents(entityId, contextKey);
      await this._loadRaceControlLog(entity, entityId, contextKey);
    }

    this._syncCurrentEntityIntoList(entity);
  }

  _syncLatestMessageState(entity = null) {
    const entityState = entity || getEntityStateWithFallback(this.hass, this.config?.entity);
    if (!entityState || entityState.state === 'unavailable' || entityState.state === 'unknown') {
      this._resetMessageState();
      return;
    }
    this._checkForNewMessage(entityState);
  }

  _unsubscribeListEvents() {
    this._callUnsubscribe(this._listEventUnsub);
    this._callUnsubscribe(this._listResetUnsub);
    this._listEventUnsub = null;
    this._listResetUnsub = null;
  }

  _callUnsubscribe(unsub) {
    if (typeof unsub !== 'function') return;
    try {
      const result = unsub();
      if (result && typeof result.catch === 'function') {
        result.catch(() => {});
      }
    } catch (_err) {
      // Ignore stale websocket subscriptions during dashboard teardown.
    }
  }

  async _subscribeListEvents(entityId, contextKey) {
    const connection = this.hass?.connection;
    if (!connection || typeof connection.subscribeEvents !== 'function') {
      return;
    }

    try {
      const eventUnsub = await connection.subscribeEvents(
        (event) => {
          if (this._listContextKey !== contextKey) return;
          this._handleRaceControlListEvent(event, entityId);
        },
        'f1_sensor_race_control_event'
      );
      if (this._listContextKey !== contextKey) {
        this._callUnsubscribe(eventUnsub);
      } else {
        this._listEventUnsub = eventUnsub;
      }
    } catch (_err) {
      // Websocket subscription is optional; list mode still works with the initial load.
    }

    try {
      const resetUnsub = await connection.subscribeEvents(
        (event) => {
          if (this._listContextKey !== contextKey) return;
          this._handleRaceControlResetEvent(event, entityId);
        },
        'f1_sensor_race_control_log_reset_event'
      );
      if (this._listContextKey !== contextKey) {
        this._callUnsubscribe(resetUnsub);
      } else {
        this._listResetUnsub = resetUnsub;
      }
    } catch (_err) {
      // Ignore missing reset subscription support and rely on optimistic UI updates.
    }
  }

  async _callWS(message) {
    if (typeof this.hass?.callWS === 'function') {
      return this.hass.callWS(message);
    }
    if (this.hass?.connection?.sendMessagePromise) {
      return this.hass.connection.sendMessagePromise(message);
    }
    throw new Error('Home Assistant websocket API is unavailable');
  }

  async _loadRaceControlLog(entity, entityId, contextKey) {
    const loadToken = ++this._listLoadToken;
    this._listLoading = true;
    this._listError = null;

    try {
      const response = await this._callWS({
        type: 'f1_sensor/race_control_log/get',
        entity_id: entityId,
      });
      if (this._listContextKey !== contextKey || loadToken !== this._listLoadToken) {
        return;
      }
      const items = Array.isArray(response?.items) ? response.items : [];
      const normalized = items
        .map((item, index) => this._normalizeListItem(item, index))
        .filter(Boolean);
      this._listMessages = this._sortListItems([...normalized, ...this._listMessages]);
      this._listLoading = false;
    } catch (_err) {
      if (this._listContextKey !== contextKey || loadToken !== this._listLoadToken) {
        return;
      }
      const fallbackItems = this._buildHistoryQueue(entity)
        .slice()
        .reverse()
        .map((item, index) => this._normalizeListItem(item, index))
        .filter(Boolean);
      this._listMessages = this._sortListItems(fallbackItems);
      this._listLoading = false;
      this._listError = fallbackItems.length > 0
        ? 'Showing recent messages only'
        : 'Full saved history is unavailable';
    }
  }

  _handleRaceControlListEvent(event, entityId) {
    const data = event?.data || {};
    const targetEntityId = data.entity_id || null;
    if (targetEntityId && targetEntityId !== entityId) {
      return;
    }
    const source = data.log_item || data.message;
    const normalized = this._normalizeListItem(source);
    if (!normalized) return;
    this._listMessages = this._sortListItems([normalized, ...this._listMessages]);
    this._listLoading = false;
    this._listError = null;
  }

  _handleRaceControlResetEvent(event, entityId) {
    const data = event?.data || {};
    if (data.entity_id && data.entity_id !== entityId) {
      return;
    }
    this._listMessages = [];
    this._listLoading = false;
    this._listError = null;
  }

  _syncCurrentEntityIntoList(entity) {
    if (!entity || entity.state === 'unavailable' || entity.state === 'unknown') {
      this._listMessages = [];
      this._listLoading = false;
      this._listError = null;
      return;
    }

    const attributes = entity.attributes || {};
    const normalized = this._normalizeListItem({
      event_id: attributes.event_id,
      utc: attributes.utc,
      received_at: attributes.received_at,
      category: attributes.category,
      flag: attributes.flag,
      scope: attributes.scope,
      sector: attributes.sector,
      car_number: attributes.car_number,
      message: attributes.message || entity.state,
      sequence: attributes.sequence,
    });

    if (!normalized) {
      return;
    }

    this._listMessages = this._sortListItems([normalized, ...this._listMessages]);
    this._listLoading = false;
    this._listError = null;
  }

  _normalizeListItem(item, fallbackIndex = 0) {
    if (!item || typeof item !== 'object') return null;
    const utc = item.utc || item.Utc || item.utc_ts || item.received_at || null;
    const category = item.category || item.Category || item.CategoryType || null;
    const flag = item.flag || item.Flag || null;
    const scope = item.scope || item.Scope || null;
    const sector = item.sector || item.Sector || item.TrackSegment || null;
    const carNumber = item.car_number || item.CarNumber || item.Number || item.Car || item.Driver || null;
    const message = item.message || item.Message || item.Text || '';
    const parsedTime = this._parseIncidentTime(utc || item.received_at || null);
    const sequenceValue = Number.parseInt(item.sequence, 10);
    const sequence = Number.isFinite(sequenceValue) ? sequenceValue : null;
    const id = item.event_id
      || item.eventId
      || [utc || '', category || '', flag || '', message || '', fallbackIndex].join('|');

    return {
      id,
      event_id: item.event_id || id,
      utc,
      received_at: item.received_at || null,
      category,
      flag,
      scope,
      sector,
      car_number: carNumber,
      message,
      sequence,
      _parsedTime: parsedTime,
    };
  }

  _sortListItems(items) {
    const unique = [];
    const seen = new Set();

    for (const item of items) {
      if (!item || !item.id) continue;
      if (seen.has(item.id)) continue;
      seen.add(item.id);
      unique.push(item);
    }

    unique.sort((a, b) => {
      const seqA = Number.isFinite(a.sequence) ? a.sequence : null;
      const seqB = Number.isFinite(b.sequence) ? b.sequence : null;
      if (seqA !== null || seqB !== null) {
        return (seqB ?? -1) - (seqA ?? -1);
      }
      const timeA = Number.isFinite(a._parsedTime) ? a._parsedTime : null;
      const timeB = Number.isFinite(b._parsedTime) ? b._parsedTime : null;
      if (timeA !== null || timeB !== null) {
        return (timeB ?? -Infinity) - (timeA ?? -Infinity);
      }
      return 0;
    });

    return unique.map((item) => {
      const normalized = { ...item };
      delete normalized._parsedTime;
      return normalized;
    });
  }

  _getVisibleListMessages() {
    return this._listMessages.filter((item) => !this._shouldHideMessage(item));
  }

  _formatListTime(value) {
    if (!value) return '--:--:--';
    const parsed = Date.parse(String(value).includes('Z') || /[+-]\d{2}:\d{2}$/.test(String(value))
      ? String(value)
      : `${String(value)}Z`);
    if (Number.isNaN(parsed)) return '--:--:--';
    const date = new Date(parsed);
    return [
      date.getHours(),
      date.getMinutes(),
      date.getSeconds(),
    ].map((part) => String(part).padStart(2, '0')).join(':');
  }

  _getListToneClass(item) {
    const flag = String(item?.flag || '').toUpperCase();
    const category = String(item?.category || '').toUpperCase();
    if (flag.includes('RED')) return 'tone-red';
    if (flag.includes('YELLOW')) return 'tone-yellow';
    if (flag === 'BLUE') return 'tone-blue';
    if (flag === 'GREEN' || flag === 'CLEAR') return 'tone-green';
    if (category === 'VSC' || category.includes('SAFETY')) return 'tone-orange';
    return 'tone-neutral';
  }

  _getListCategoryLabel(item) {
    const flag = String(item?.flag || '').trim();
    const category = String(item?.category || '').trim();
    if (flag) return flag;
    if (category) return category;
    return 'Race Control';
  }

  async _handleClearList(ev) {
    ev?.stopPropagation?.();
    if (this._isClearing) return;
    const entityId = resolveEntityIdWithFallback(this.hass, this.config?.entity);
    if (!entityId || typeof this.hass?.callService !== 'function') return;

    this._isClearing = true;
    try {
      await this.hass.callService('f1_sensor', 'clear_race_control_log', {
        entity_id: entityId,
      });
      this._listMessages = [];
      this._listError = null;
    } catch (_err) {
      this._listError = 'Could not clear saved messages';
    } finally {
      this._isClearing = false;
    }
  }

  _checkForNewMessage(entity = null) {
    const entityState = entity || getEntityStateWithFallback(this.hass, this.config?.entity);
    if (!entityState || entityState.state === 'unavailable' || entityState.state === 'unknown') return;

    const minDisplayTime = this.config?.min_display_time || 0;
    const queue = this._buildHistoryQueue(entityState);
    const currentId = this._currentMessage?.id || this._lastEventId;
    const historyChanged = this._historyChanged(queue);

    if (queue.length === 0) {
      this._resetMessageState();
      return;
    }

    if (minDisplayTime > 0) {
      const currentIndex = currentId
        ? queue.findIndex((item) => item?.id === currentId)
        : -1;
      const shouldResetToStart = historyChanged && currentIndex === -1;
      const nextIndex = currentIndex >= 0 ? currentIndex : 0;
      const nextMessage = queue[nextIndex];
      const nextId = nextMessage?.id || null;

      if (!this._currentMessage || this._currentMessage.id !== nextId) {
        this._showMessage(nextMessage, { resetTimer: shouldResetToStart });
      }

      this._historyQueue = queue;
      this._historyIndex = nextIndex;
      this._ensureQueueTimer(minDisplayTime, this._historyQueue.length);
      return;
    }

    this._historyQueue = queue;
    this._historyIndex = queue.length - 1;
    this._clearDisplayTimer();
    this._showMessage(queue[this._historyIndex]);
  }

  _showMessage(msg, options = {}) {
    const { resetTimer = false } = options;
    if (resetTimer) {
      this._clearDisplayTimer();
    }
    this._currentMessage = msg;
    this._lastEventId = msg?.id || null;
    this._messageShownAt = msg ? Date.now() : 0;
  }

  _showNextFromQueue() {
    if (this._historyQueue.length === 0) {
      this._clearDisplayTimer();
      return;
    }
    const nextIndex = this._historyIndex + 1;
    if (nextIndex >= this._historyQueue.length) {
      this._clearDisplayTimer();
      return;
    }
    this._historyIndex = nextIndex;
    this._showMessage(this._historyQueue[this._historyIndex], { resetTimer: true });
    this.requestUpdate();
    const minDisplayTime = this.config?.min_display_time || 0;
    if (minDisplayTime > 0 && this._historyIndex < this._historyQueue.length - 1) {
      this._displayTimer = setTimeout(() => {
        this._showNextFromQueue();
      }, minDisplayTime * 1000);
    } else {
      this._clearDisplayTimer();
    }
  }

  setConfig(config) {
    this.config = {
      theme_mode: DEFAULT_F1_THEME_MODE,
      entity: 'sensor.f1_race_control',
      show_fia_logo: true,
      hide_blue_flags: false,
      hide_track_limits: false,
      min_display_time: 0,
      ...config,
    };
    applyF1ThemeMode(this, this.config);
  }

  static getConfigElement() {
    return document.createElement('f1-race-control-card-editor');
  }

  static getStubConfig() {
    return {
      type: 'custom:f1-race-control-card',
      entity: '',
    };
  }

  getCardSize() {
    if (this._isListMode()) {
      return Math.max(3, Math.ceil(this._normalizeListMaxHeight(this.config?.list_max_height) / 120));
    }
    return 1;
  }

  getGridOptions() {
    if (this._isListMode()) {
      return {
        columns: 12,
        min_columns: 6,
        max_columns: 12,
        min_rows: 3,
      };
    }

    return {
      columns: 12,
      min_columns: 6,
      max_columns: 12,
      min_rows: 1,
    };
  }

  _formatMessage(message) {
    if (!message) return '';
    return this._stripEmbeddedTime(String(message));
  }

  _buildHistoryQueue(entity) {
    const history = Array.isArray(entity?.attributes?.history)
      ? entity.attributes.history
      : [];
    const queue = history
      .map((item, index) => {
        if (!item) return null;
        const utc = item.utc || entity.attributes?.utc || null;
        const parsed = this._parseIncidentTime(utc);
        const id = item.event_id || `${item.utc || ''}|${item.message || ''}|${index}`;
        return {
          id,
          message: item.message || entity.attributes?.message || entity.state,
          category: item.category || null,
          flag: item.flag || null,
          car_number: null,
          utc,
          _time: parsed,
        };
      })
      .filter((item) => !this._shouldHideMessage(item))
      .filter(Boolean);
    if (queue.length > 0) {
      const hasTime = queue.some((item) => Number.isFinite(item._time));
      if (hasTime) {
        queue.sort((a, b) => (a._time ?? Infinity) - (b._time ?? Infinity));
      } else {
        queue.reverse();
      }
      queue.forEach((item) => delete item._time);
      return queue;
    }
    const fallbackId = entity.attributes?.event_id || entity.attributes?.utc || entity.state;
    if (!fallbackId) return [];
    const fallbackItem = {
      id: fallbackId,
      message: entity.attributes?.message || entity.state,
      category: entity.attributes?.category || null,
      flag: entity.attributes?.flag || null,
      car_number: entity.attributes?.car_number || null,
      utc: entity.attributes?.utc || null,
    };
    return this._shouldHideMessage(fallbackItem) ? [] : [fallbackItem];
  }

  _historyChanged(queue) {
    if (!Array.isArray(queue) || queue.length === 0) return this._historyQueue.length !== 0;
    if (queue.length !== this._historyQueue.length) return true;
    return queue.some((item, index) => item?.id !== this._historyQueue[index]?.id);
  }

  _shouldHideMessage(item) {
    if (!item) return true;
    if (this.config?.hide_blue_flags === true && this._isBlueFlagMessage(item)) {
      return true;
    }
    return this.config?.hide_track_limits === true && this._isTrackLimitsMessage(item);
  }

  _isBlueFlagMessage(item) {
    const flag = String(item?.flag || '').trim().toUpperCase();
    if (flag === 'BLUE') return true;
    if (flag) return false;

    const message = this._formatMessage(item?.message || '').toLowerCase();
    return message.includes('waved blue flag') || message.includes('blue flag');
  }

  _isTrackLimitsMessage(item) {
    const message = this._formatMessage(item?.message || '').toUpperCase();
    return message.includes('TRACK LIMITS');
  }

  _parseIncidentTime(value) {
    if (!value) return null;
    const text = String(value).trim();
    if (!text) return null;
    const normalized = text.includes('Z') || /[+-]\d{2}:\d{2}$/.test(text)
      ? text
      : `${text}Z`;
    const ts = Date.parse(normalized);
    return Number.isNaN(ts) ? null : ts;
  }

  _ensureQueueTimer(minDisplayTime, queueLength) {
    if (minDisplayTime <= 0 || queueLength <= 1) {
      this._clearDisplayTimer();
      return;
    }
    if (this._historyIndex >= queueLength - 1) {
      this._clearDisplayTimer();
      return;
    }
    if (!this._displayTimer) {
      this._displayTimer = setTimeout(() => {
        this._showNextFromQueue();
      }, minDisplayTime * 1000);
    }
  }

  _stripEmbeddedTime(message) {
    // Remove trailing track-local time like "17:08:15" or "17.08.15" from race control text.
    let cleaned = message.replace(/\s\d{1,2}[:.]\d{2}[:.]\d{2}(?=\s*\(PIT\)$|\s*$)/, '');
    cleaned = cleaned.replace(/\s{2,}/g, ' ').trim();
    return cleaned;
  }

  render() {
    if (!this.hass || !this.config) {
      const showLogo = this.config?.show_fia_logo;
      return html`
        <ha-card>
          <div class="rc-card rc-unavailable">
            ${showLogo ? html`<img class="rc-fia-logo" src="https://www.fia.com/sites/all/themes/penceo_theme/images/fia-footer-logo.png" alt="FIA" />` : null}
            <span class="rc-unavailable-text">Loading...</span>
          </div>
        </ha-card>
      `;
    }

    const currentEntity = getEntityStateWithFallback(this.hass, this.config.entity);
    if (this._isListMode()) {
      return this._renderListMode(currentEntity);
    }

    return this._renderLatestMode(currentEntity);
  }

  _renderLatestMode(currentEntity) {
    if (!currentEntity || currentEntity.state === 'unavailable' || currentEntity.state === 'unknown') {
      const showLogo = this.config.show_fia_logo;
      return html`
        <ha-card>
          <div class="rc-card rc-unavailable">
            ${showLogo ? html`<img class="rc-fia-logo" src="https://www.fia.com/sites/all/themes/penceo_theme/images/fia-footer-logo.png" alt="FIA" />` : null}
            <span class="rc-unavailable-text">No session data</span>
          </div>
        </ha-card>
      `;
    }

    if (!this._currentMessage) {
      const showLogo = this.config.show_fia_logo;
      return html`
        <ha-card>
          <div class="rc-card rc-unavailable">
            ${showLogo ? html`<img class="rc-fia-logo" src="https://www.fia.com/sites/all/themes/penceo_theme/images/fia-footer-logo.png" alt="FIA" />` : null}
            <span class="rc-unavailable-text">No visible race control messages</span>
          </div>
        </ha-card>
      `;
    }

    const msg = this._currentMessage;
    const formattedMessage = this._formatMessage(msg.message);
    const queueCount = (this.config?.min_display_time || 0) > 0
      ? Math.max(0, this._historyQueue.length - 1 - this._historyIndex)
      : 0;
    const criticalClass = this._getCriticalClass(msg);
    const messageClass = this._getMessageCategoryClass(msg);

    return html`
      <ha-card>
        <div class="rc-card ${criticalClass}">
          ${this.config.show_fia_logo ? html`
            <img class="rc-fia-logo" src="https://www.fia.com/sites/all/themes/penceo_theme/images/fia-footer-logo.png" alt="FIA" />
          ` : null}

          <div class="rc-content">
            <div class="rc-message ${messageClass}">${formattedMessage}</div>
            ${queueCount > 0 ? html`
              <span class="rc-queue-indicator">+${queueCount}</span>
            ` : null}
          </div>

        </div>
      </ha-card>
    `;
  }

  _renderListMode(currentEntity) {
    if (!currentEntity) {
      const showLogo = this.config.show_fia_logo;
      return html`
        <ha-card>
          <div class="rc-card rc-unavailable">
            ${showLogo ? html`<img class="rc-fia-logo" src="https://www.fia.com/sites/all/themes/penceo_theme/images/fia-footer-logo.png" alt="FIA" />` : null}
            <span class="rc-unavailable-text">No session data</span>
          </div>
        </ha-card>
      `;
    }

    const totalCount = this._listMessages.length;
    const visibleMessages = this._getVisibleListMessages();
    const visibleCount = visibleMessages.length;
    const showLogo = this.config.show_fia_logo;
    const live = currentEntity.state !== 'unavailable' && currentEntity.state !== 'unknown';
    const statusLabel = live ? 'Live' : 'Saved';
    const countLabel = totalCount === visibleCount
      ? `${totalCount} ${totalCount === 1 ? 'message' : 'messages'}`
      : `${visibleCount} of ${totalCount} messages`;
    const maxHeight = this._normalizeListMaxHeight(this.config?.list_max_height);
    const bodyStyle = maxHeight > 0 ? `max-height: ${maxHeight}px;` : '';

    let emptyText = 'No saved race control messages yet';
    if (this._listLoading) {
      emptyText = 'Loading saved race control messages';
    } else if (totalCount > 0 && visibleCount === 0) {
      emptyText = 'No visible race control messages';
    }

    return html`
      <ha-card>
        <div class="rc-list-shell">
          <div class="rc-list-topbar">
            <div class="rc-list-brand">
              ${showLogo ? html`<img class="rc-fia-logo" src="https://www.fia.com/sites/all/themes/penceo_theme/images/fia-footer-logo.png" alt="FIA" />` : null}
              <div class="rc-list-title-wrap">
                <span class="rc-list-title">Race Control</span>
                <span class="rc-list-count">${countLabel}</span>
              </div>
            </div>
            <div class="rc-list-controls">
              <span class="rc-live-pill ${live ? '' : 'saved'}">${statusLabel}</span>
              ${this.config.show_clear_button !== false ? html`
                <button
                  class="rc-clear-button"
                  ?disabled=${this._isClearing}
                  @click=${this._handleClearList}
                >
                  ${this._isClearing ? 'Clearing' : 'Clear'}
                </button>
              ` : null}
            </div>
          </div>

          ${this._listError ? html`
            <div class="rc-list-warning">${this._listError}</div>
          ` : null}

          <div class="rc-list-body" style=${bodyStyle}>
            ${visibleCount > 0 ? visibleMessages.map((item) => html`
              <div class="rc-list-row ${this._getListToneClass(item)}">
                <div class="rc-list-meta">
                  ${item.sequence ? html`<span class="rc-list-sequence">#${item.sequence}</span>` : null}
                  <span class="rc-list-time">${this._formatListTime(item.utc || item.received_at)}</span>
                </div>
                <div class="rc-list-content">
                  <span class="rc-list-category">${this._getListCategoryLabel(item)}</span>
                  <span class="rc-list-message">${this._formatMessage(item.message)}</span>
                </div>
              </div>
            `) : html`
              <div class="rc-list-empty">${emptyText}</div>
            `}
          </div>
        </div>
      </ha-card>
    `;
  }

  _getCriticalClass(msg) {
    const cat = String(msg?.category || '').toUpperCase();
    const flag = String(msg?.flag || '').toUpperCase();
    if (flag === 'RED' || flag.includes('RED')) return 'critical';
    if (cat === 'SAFETYCAR' || cat === 'VSC' || cat.includes('SAFETY')) return 'critical-sc';
    return '';
  }

  _getMessageCategoryClass(msg) {
    const cat = String(msg?.category || '').toLowerCase();
    if (cat.includes('safety') || cat === 'vsc') return 'category-safetycar';
    if (cat.includes('penalty')) return 'category-penalty';
    return '';
  }
}

class F1RaceControlCardEditor extends LitElement {
  static properties = {
    hass: {},
    _config: {},
    _activeTab: { state: true },
  };

  static styles = css`
    .card-config {
      display: flex;
      flex-direction: column;
    }

    .tabs {
      display: flex;
      border-bottom: 1px solid var(--divider-color);
      margin-bottom: 16px;
    }

    .tabs button {
      flex: 1;
      padding: 12px;
      background: none;
      border: none;
      cursor: pointer;
      color: var(--primary-text-color);
      font-size: 14px;
      font-family: inherit;
      transition: color 0.2s;
    }

    .tabs button:hover {
      color: var(--primary-color);
    }

    .tabs button.active {
      color: var(--primary-color);
      border-bottom: 2px solid var(--primary-color);
      margin-bottom: -1px;
    }

    .section {
      display: flex;
      flex-direction: column;
      gap: 16px;
      margin-bottom: 16px;
    }

    .section-header {
      font-size: 11px;
      font-weight: 700;
      letter-spacing: 0.5px;
      color: var(--secondary-text-color);
      text-transform: uppercase;
      margin-top: 8px;
    }

    .field {
      display: flex;
      flex-direction: column;
      gap: 4px;
    }

    .helper {
      font-size: 12px;
      color: var(--secondary-text-color);
      padding-left: 16px;
      line-height: 1.4;
    }

    .warning {
      font-size: 12px;
      color: var(--error-color);
      padding-left: 16px;
    }

    .display-section {
      display: flex;
      flex-direction: column;
      gap: 12px;
    }

    ha-textfield {
      display: block;
      margin-bottom: 8px;
    }

    ha-formfield {
      display: flex;
      align-items: center;
      padding: 4px 0;
    }

    ha-form {
      width: 100%;
    }
  `;

  constructor() {
    super();
    this._activeTab = 'sources';
  }

  setConfig(config) {
    this._config = this._normalizeConfig({
      display_mode: 'latest',
      show_fia_logo: true,
      hide_blue_flags: false,
      hide_track_limits: false,
      min_display_time: 0,
      list_max_height: 600,
      show_clear_button: true,
      ...config,
    });
  }

  _normalizeConfig(config) {
    if (!config || typeof config !== 'object') {
      return config;
    }

    const normalized = { ...config };
    const displayMode = normalized.display_mode === 'list' ? 'list' : 'latest';
    normalized.display_mode = displayMode;

    if (displayMode !== 'list') {
      return normalized;
    }

    const gridOptions = normalized.grid_options && typeof normalized.grid_options === 'object'
      ? { ...normalized.grid_options }
      : {};

    gridOptions.columns = gridOptions.columns ?? 'full';
    gridOptions.rows = 'auto';
    normalized.grid_options = gridOptions;
    return normalized;
  }

  render() {
    if (!this.hass || !this._config) return html``;

    return html`
      <div class="card-config">
        <div class="tabs">
          <button
            class=${this._activeTab === 'sources' ? 'active' : ''}
            @click=${() => this._activeTab = 'sources'}
          >
            Data Sources
          </button>
          <button
            class=${this._activeTab === 'display' ? 'active' : ''}
            @click=${() => this._activeTab = 'display'}
          >
            Display
          </button>
        </div>

        ${this._activeTab === 'sources'
          ? this._renderDataSourcesTab()
          : this._renderDisplayTab()}
      </div>
    `;
  }

  _renderDataSourcesTab() {
    return html`
      <div class="section">
        <div class="section-header">REQUIRED SENSORS</div>
        ${this._renderEntityPicker(
          'entity',
          'Race Control Sensor',
          'Provides race control messages and decisions',
          true,
          'sensor'
        )}
      </div>
    `;
  }

  _renderDisplayTab() {
    return html`
      <div class="display-section">
        ${renderThemeModeSelect(this)}
        ${this._renderSelect(
          'display_mode',
          'Display mode',
          [
            { value: 'latest', label: 'Latest banner' },
            { value: 'list', label: 'Saved message list' },
          ]
        )}
        <div class="helper">Choose between the current compact banner and a full saved session list</div>

        ${this._renderSwitch('show_fia_logo', 'Show FIA logo')}
        ${this._renderSwitch(
          'hide_blue_flags',
          'Hide blue flag messages',
          'Remove blue flag notices from the banner or list without deleting them from saved history'
        )}
        ${this._renderSwitch(
          'hide_track_limits',
          'Hide track limits messages',
          'Remove track limits notices from the banner or list without deleting them from saved history'
        )}

        ${this._config.display_mode === 'list' ? html`
          <ha-textfield
            .label=${'List max height (px)'}
            .value=${String(this._config.list_max_height || 600)}
            type="number"
            min="240"
            max="2000"
            @input=${(e) => this._valueChanged('list_max_height', parseInt(e.target.value, 10) || 600)}
          ></ha-textfield>
          <div class="helper">Controls how tall the saved message list can grow before it scrolls</div>

          ${this._renderSwitch(
            'show_clear_button',
            'Show clear button',
            'Lets users clear the saved log for the current session directly from the card'
          )}
        ` : html`
          <ha-textfield
            .label=${'Min display time per message (seconds)'}
            .value=${String(this._config.min_display_time || 0)}
            type="number"
            min="0"
            max="30"
            @input=${(e) => this._valueChanged('min_display_time', parseInt(e.target.value, 10) || 0)}
          ></ha-textfield>
          <div class="helper">Set to 0 to disable minimum display time</div>
        `}
      </div>
    `;
  }

  _renderEntityPicker(name, label, helper, required, domain) {
    const value = this._config[name];
    const showWarning = required && !value;
    const schema = [{ name, label, required, selector: { entity: { domain } } }];

    return html`
      <div class="field">
        <ha-form
          .hass=${this.hass}
          .data=${this._config}
          .schema=${schema}
          .computeLabel=${() => label}
          @value-changed=${this._formValueChanged}
        ></ha-form>
        <div class="helper">${helper}</div>
        ${showWarning ? html`
          <div class="warning">This sensor is required for the card to function</div>
        ` : ''}
      </div>
    `;
  }

  _renderSwitch(name, label, helper = null) {
    const schema = [{ name, label, selector: { boolean: {} } }];
    return html`
      <ha-form
        .hass=${this.hass}
        .data=${this._config}
        .schema=${schema}
        .computeLabel=${() => label}
        @value-changed=${this._formValueChanged}
      ></ha-form>
      ${helper ? html`<div class="helper">${helper}</div>` : ''}
    `;
  }

  _renderSelect(name, label, options) {
    const schema = [
      {
        name,
        label,
        selector: {
          select: {
            mode: 'dropdown',
            options,
          },
        },
      },
    ];
    return html`
      <ha-form
        .hass=${this.hass}
        .data=${this._config}
        .schema=${schema}
        .computeLabel=${() => label}
        @value-changed=${this._formValueChanged}
      ></ha-form>
    `;
  }

  _formValueChanged(ev) {
    if (!this._config) return;
    const value = ev.detail?.value || {};
    const newConfig = this._normalizeConfig({ ...this._config, ...value });
    this._config = newConfig;
    this.dispatchEvent(new CustomEvent('config-changed', { detail: { config: newConfig } }));
  }

  _valueChanged(name, value) {
    if (!this._config) return;
    const newConfig = this._normalizeConfig({ ...this._config, [name]: value });
    this._config = newConfig;
    this.dispatchEvent(new CustomEvent('config-changed', { detail: { config: newConfig } }));
  }
}


